		if schema.Body == nil {
			return changesSrc, fmt.Errorf("Changes.Encode: missing schema for %s", qi.Addr)
		}
		rcs, err := qi.Encode(schema)
		if err != nil {
			return changesSrc, fmt.Errorf("Changes.Encode: %w", err)
		}

		changesSrc.Queries = append(changesSrc.Queries, rcs)
	}

