     3→
     4→package format
     5→
     6→import (
     7→	"bytes"
     8→	"fmt"
     9→	"sort"
    10→
    11→	"github.com/hashicorp/terraform/internal/addrs"
    12→	"github.com/hashicorp/terraform/internal/plans"
    13→	"github.com/hashicorp/terraform/internal/schemarepo"
    14→)
    15→
    16→// CompactDiffFormatter is a plan formatter that produces a condensed,
    17→// summary-style diff output showing only resource-level changes
    18→// without attribute-level detail.
    19→type CompactDiffFormatter struct{}
    20→
    21→// Format produces a compact, summary-style diff output for a plan.
    22→// It shows one line per resource change: [action] resource_type.name
    23→// Groups changes by action type and shows summary counts at the end.
    24→func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
    25→	var buf bytes.Buffer
    26→
    27→	if plan == nil || plan.Changes == nil {
    28→		return ""
    29→	}
    30→
    31→	// Group resources by action
    32→	changes := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)
    33→	for _, resource := range plan.Changes.Resources {
    34→		if resource == nil {
    35→			continue
    36→		}
    37→		// Skip NoOp actions unless we need to show them
    38→		if resource.Action != plans.NoOp {
    39→			changes[resource.Action] = append(changes[resource.Action], resource)
    40→		}
    41→	}
    42→
    43→	// Define the order to display action types
    44→	actionOrder := []plans.Action{
    45→		plans.Create,
    46→		plans.Update,
    47→		plans.Delete,
    48→		plans.DeleteThenCreate,
    49→		plans.CreateThenDelete,
    50→		plans.Read,
    51→		plans.Forget,
    52→		plans.CreateThenForget,
    53→	}
    54→
    55→	// Track counts for summary
    56→	counts := make(map[plans.Action]int)
    57→	actionStrings := make(map[plans.Action]string)
    58→	actionStrings[plans.Create] = "create"
    59→	actionStrings[plans.Update] = "update"
    60→	actionStrings[plans.Delete] = "delete"
    61→	actionStrings[plans.DeleteThenCreate] = "replace"
    62→	actionStrings[plans.CreateThenDelete] = "replace"
    63→	actionStrings[plans.Read] = "read"
    64→	actionStrings[plans.Forget] = "forget"
    65→	actionStrings[plans.CreateThenForget] = "replace"
    66→
    67→	// Display changes grouped by action
    68→	for _, action := range actionOrder {
    69→		resources := changes[action]
    70→		if len(resources) == 0 {
    71→			continue
    72→		}
    73→
    74→		// Sort resources by address for consistent output
    75→		sort.Slice(resources, func(i, j int) bool {
    76→			return resources[i].Addr.String() < resources[j].Addr.String()
    77→		})
    78→
    79→		actionStr := actionStrings[action]
    80→		counts[action] = len(resources)
    81→
    82→		for _, resource := range resources {
    83→			if resource == nil {
    84→				continue
    85→			}
    86→			addr := resource.Addr.String()
    87→			fmt.Fprintf(&buf, "[%s] %s\n", actionStr, addr)
    88→		}
    89→	}
    90→
    91→	// Add summary counts if there are any changes
    92→	hasChanges := false
    93→	for _, count := range counts {
    94→		if count > 0 {
    95→			hasChanges = true
    96→			break
    97→		}
    98→	}
    99→
   100→	if hasChanges {
   101→		buf.WriteString("\n")
   102→		summaryItems := []string{}
   103→
   104→		// Build summary in order
   105→		createCount := counts[plans.Create]
   106→		if createCount > 0 {
   107→			summaryItems = append(summaryItems, fmt.Sprintf("Plan: %d to add", createCount))
   108→		}
   109→
   110→		updateCount := counts[plans.Update]
   111→		if updateCount > 0 {
   112→			summaryItems = append(summaryItems, fmt.Sprintf("%d to change", updateCount))
   113→		}
   114→
   115→		replaceCount := counts[plans.DeleteThenCreate] + counts[plans.CreateThenDelete]
   116→		if replaceCount > 0 {
   117→			summaryItems = append(summaryItems, fmt.Sprintf("%d to replace", replaceCount))
   118→		}
   119→
   120→		deleteCount := counts[plans.Delete]
   121→		if deleteCount > 0 {
   122→			summaryItems = append(summaryItems, fmt.Sprintf("%d to destroy", deleteCount))
   123→		}
   124→
   125→		readCount := counts[plans.Read]
   126→		if readCount > 0 {
   127→			summaryItems = append(summaryItems, fmt.Sprintf("%d to read", readCount))
   128→		}
   129→
   130→		forgetCount := counts[plans.Forget]
   131→		if forgetCount > 0 {
   132→			summaryItems = append(summaryItems, fmt.Sprintf("%d to forget", forgetCount))
   133→		}
   134→
   135→		forgetReplaceCount := counts[plans.CreateThenForget]
   136→		if forgetReplaceCount > 0 {
   137→			summaryItems = append(summaryItems, fmt.Sprintf("%d to replace and forget", forgetReplaceCount))
   138→		}
   139→
   140→		// Write summary
   141→		summary := ""
   142→		for i, item := range summaryItems {
   143→			if i == 0 {
   144→				summary = item
   145→			} else {
   146→				summary += ", " + item
   147→			}
   148→		}
   149→		fmt.Fprintf(&buf, "%s.\n", summary)
   150→	}
   151→
   152→	return buf.String()
   153→}
