package format

import (
	"bytes"
	"fmt"
	"sort"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
)

// CompactDiffFormatter is a plan formatter that produces a condensed,
// summary-style diff output showing only resource-level changes
// without attribute-level detail.
type CompactDiffFormatter struct{}

// Format produces a compact, summary-style diff output for a plan.
// It shows one line per resource change: [action] resource_type.name
// Groups changes by action type and shows summary counts at the end.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	var buf bytes.Buffer

	if plan == nil || plan.Changes == nil {
		return ""
	}

	// Group resources by action
	changes := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)
	for _, resource := range plan.Changes.Resources {
		if resource == nil {
			continue
		}
		// Skip NoOp actions unless we need to show them
		if resource.Action != plans.NoOp {
			changes[resource.Action] = append(changes[resource.Action], resource)
		}
	}

	// Define the order to display action types
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.Delete,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.Read,
		plans.Forget,
		plans.CreateThenForget,
	}

	// Track counts for summary
	counts := make(map[plans.Action]int)
	actionStrings := make(map[plans.Action]string)
	actionStrings[plans.Create] = "create"
	actionStrings[plans.Update] = "update"
	actionStrings[plans.Delete] = "delete"
	actionStrings[plans.DeleteThenCreate] = "replace"
	actionStrings[plans.CreateThenDelete] = "replace"
	actionStrings[plans.Read] = "read"
	actionStrings[plans.Forget] = "forget"
	actionStrings[plans.CreateThenForget] = "replace"

	// Display changes grouped by action
	for _, action := range actionOrder {
		resources := changes[action]
		if len(resources) == 0 {
			continue
		}

		// Sort resources by address for consistent output
		sort.Slice(resources, func(i, j int) bool {
			return resources[i].Addr.String() < resources[j].Addr.String()
		})

		actionStr := actionStrings[action]
		counts[action] = len(resources)

		for _, resource := range resources {
			if resource == nil {
				continue
			}
			addr := resource.Addr.String()
			fmt.Fprintf(&buf, "[%s] %s\n", actionStr, addr)
		}
	}

	// Add summary counts if there are any changes
	hasChanges := false
	for _, count := range counts {
		if count > 0 {
			hasChanges = true
			break
		}
	}

	if hasChanges {
		buf.WriteString("\n")
		summaryItems := []string{}

		// Build summary in order
		createCount := counts[plans.Create]
		if createCount > 0 {
			summaryItems = append(summaryItems, fmt.Sprintf("Plan: %d to add", createCount))
		}

		updateCount := counts[plans.Update]
		if updateCount > 0 {
			summaryItems = append(summaryItems, fmt.Sprintf("%d to change", updateCount))
		}

		replaceCount := counts[plans.DeleteThenCreate] + counts[plans.CreateThenDelete]
		if replaceCount > 0 {
			summaryItems = append(summaryItems, fmt.Sprintf("%d to replace", replaceCount))
		}

		deleteCount := counts[plans.Delete]
		if deleteCount > 0 {
			summaryItems = append(summaryItems, fmt.Sprintf("%d to destroy", deleteCount))
		}

		readCount := counts[plans.Read]
		if readCount > 0 {
			summaryItems = append(summaryItems, fmt.Sprintf("%d to read", readCount))
		}

		forgetCount := counts[plans.Forget]
		if forgetCount > 0 {
			summaryItems = append(summaryItems, fmt.Sprintf("%d to forget", forgetCount))
		}

		forgetReplaceCount := counts[plans.CreateThenForget]
		if forgetReplaceCount > 0 {
			summaryItems = append(summaryItems, fmt.Sprintf("%d to replace and forget", forgetReplaceCount))
		}

		// Write summary
		summary := ""
		for i, item := range summaryItems {
			if i == 0 {
				summary = item
			} else {
				summary += ", " + item
			}
		}
		fmt.Fprintf(&buf, "%s.\n", summary)
	}

	return buf.String()
}

